     1→/// Configuration types for yokushi suppression rules.
     2→///
     3→/// Loaded from YAML; config discovery order:
     4→/// 1. --config CLI flag
     5→/// 2. YOKUSHI_CONFIG env var
     6→/// 3. ./yokushi.yaml
     7→/// 4. ~/.config/yokushi/config.yaml
     8→use std::collections::HashMap;
     9→use std::path::PathBuf;
    10→
    11→use anyhow::{Context, Result};
    12→use serde::Deserialize;
    13→
    14→use crate::output::OutputMode;
    15→
    16→/// A single suppression rule.
    17→#[derive(Debug, Deserialize)]
    18→pub struct Rule {
    19→    /// Tool name to match (default: "Bash").
    20→    pub tool: Option<String>,
    21→    /// Field in tool_input to match against (default: auto-detected per tool).
    22→    pub field: Option<String>,
    23→    /// Regex pattern to match the field value.
    24→    pub pattern: String,
    25→    /// Human-readable reason shown when the rule blocks.
    26→    pub message: String,
    27→}
    28→
    29→impl Rule {
    30→    /// Returns the effective tool name (defaults to "Bash").
    31→    pub fn effective_tool(&self) -> &str {
    32→        self.tool.as_deref().unwrap_or("Bash")
    33→    }
    34→
    35→    /// Returns the effective field name, auto-detected from the tool when not specified.
    36→    pub fn effective_field(&self) -> &str {
    37→        if let Some(f) = &self.field {
    38→            return f.as_str();
    39→        }
    40→        default_field(self.effective_tool())
    41→    }
    42→}
    43→
    44→/// Per-agent output configuration.
    45→#[derive(Debug, Deserialize)]
    46→pub struct AgentConfig {
    47→    pub output: OutputMode,
    48→}
    49→
    50→/// Root configuration structure.
    51→#[derive(Debug, Deserialize)]
    52→pub struct Config {
    53→    /// Agent-specific output behavior keyed by agent name.
    54→    #[serde(default)]
    55→    pub agents: HashMap<String, AgentConfig>,
    56→    /// Ordered list of suppression rules.
    57→    #[serde(default)]
    58→    pub rules: Vec<Rule>,
    59→}
    60→
    61→impl Config {
    62→    /// Returns the output mode for the given agent name.
    63→    /// Falls back to the "default" agent config, then to `OutputMode::Exit`.
    64→    pub fn output_mode_for(&self, agent: &str) -> OutputMode {
    65→        if let Some(cfg) = self.agents.get(agent) {
    66→            return cfg.output;
    67→        }
    68→        if let Some(cfg) = self.agents.get("default") {
    69→            return cfg.output;
    70→        }
    71→        OutputMode::Exit
    72→    }
    73→}
    74→
    75→/// Returns the default tool_input field name for a given tool.
    76→pub fn default_field(tool: &str) -> &str {
    77→    match tool {
    78→        "Bash" => "command",
    79→        "Write" | "Edit" | "Read" | "Glob" | "Grep" => "file_path",
    80→        "WebFetch" => "url",
    81→        "WebSearch" => "query",
    82→        "Task" => "prompt",
    83→        _ => "command",
    84→    }
    85→}
    86→
    87→/// Loads config from the given path.
    88→pub fn load_from_path(path: &PathBuf) -> Result<Config> {
    89→    let content = std::fs::read_to_string(path)
    90→        .with_context(|| format!("Failed to read config file: {}", path.display()))?;
    91→    serde_yml::from_str(&content)
    92→        .with_context(|| format!("Failed to parse config file: {}", path.display()))
    93→}
    94→
    95→/// Discovers and loads the config file using the standard search order.
    96→/// Returns `None` if no config file is found (allow-all mode).
    97→pub fn discover(explicit_path: Option<&PathBuf>) -> Result<Option<Config>> {
    98→    // 1. Explicit --config flag
    99→    if let Some(path) = explicit_path {
   100→        return load_from_path(path).map(Some);
   101→    }
   102→
   103→    // 2. YOKUSHI_CONFIG environment variable
   104→    if let Ok(env_path) = std::env::var("YOKUSHI_CONFIG") {
   105→        return load_from_path(&PathBuf::from(env_path)).map(Some);
   106→    }
   107→
   108→    // 3. ./yokushi.yaml
   109→    let local = PathBuf::from("yokushi.yaml");
   110→    if local.exists() {
   111→        return load_from_path(&local).map(Some);
   112→    }
   113→
   114→    // 4. ~/.config/yokushi/config.yaml
   115→    if let Some(home) = dirs_next() {
   116→        let global = home.join(".config/yokushi/config.yaml");
   117→        if global.exists() {
   118→            return load_from_path(&global).map(Some);
   119→        }
   120→    }
   121→
   122→    Ok(None)
   123→}
   124→
   125→/// Returns the home directory path.
   126→fn dirs_next() -> Option<PathBuf> {
   127→    std::env::var("HOME").ok().map(PathBuf::from)
   128→}
