   136→        assert_eq!(default_field("Bash"), "command");
   137→        assert_eq!(default_field("Write"), "file_path");
   138→        assert_eq!(default_field("Edit"), "file_path");
   139→        assert_eq!(default_field("Read"), "file_path");
   140→        assert_eq!(default_field("WebFetch"), "url");
   141→        assert_eq!(default_field("WebSearch"), "query");
   142→        assert_eq!(default_field("Task"), "prompt");
   143→        assert_eq!(default_field("Unknown"), "command");
   144→    }
   145→
   146→    #[test]
   147→    fn test_rule_defaults() {
   148→        let rule = Rule {
   149→            tool: None,
   150→            field: None,
   151→            pattern: "git push".into(),
   152→            message: "blocked".into(),
   153→        };
   154→        assert_eq!(rule.effective_tool(), "Bash");
   155→        assert_eq!(rule.effective_field(), "command");
   156→    }
   157→
   158→    #[test]
   159→    fn test_rule_with_tool() {
   160→        let rule = Rule {
   161→            tool: Some("Write".into()),
   162→            field: None,
   163→            pattern: "\\.env$".into(),
   164→            message: "blocked".into(),
   165→        };
   166→        assert_eq!(rule.effective_tool(), "Write");
   167→        assert_eq!(rule.effective_field(), "file_path");
   168→    }
   169→
   170→    #[test]
   171→    fn test_parse_config_yaml() {
   172→        let yaml = r#"
   173→version: "1"
